const slug = $('Book Research').item.json.book_slug;
const optionalResearch = $('Book Research').item.json['Paste NotebookLM or external research here'] || '';
const libraryContent = $('Read Library').item.json.content || '(knowledge vault empty — first book)';
let systemPrompt = $('Read Prompt').item.json.content;

if (!systemPrompt) {
  throw new Error('Research prompt not found at n8n/prompts/research.md');
}

// Replace placeholders
systemPrompt = systemPrompt.replace(/\{\{book_slug\}\}/g, slug);
systemPrompt = systemPrompt.replace(/\{\{vault_library\}\}/g, libraryContent);

// Set optional vault placeholders to empty if not available
systemPrompt = systemPrompt.replace(/\{\{vault_authors\}\}/g, '(not available)');
systemPrompt = systemPrompt.replace(/\{\{vault_concepts\}\}/g, '(not available)');
systemPrompt = systemPrompt.replace(/\{\{vault_connections\}\}/g, '(not available)');
systemPrompt = systemPrompt.replace(/\{\{narrative_templates\}\}/g, '(not available)');

// Inject optional research if provided
if (optionalResearch.trim()) {
  systemPrompt += '\n\n## Additional Research (provided by user)\n\n' + optionalResearch.trim();
}

const userMessage = "Research the book '" + slug + "' and propose 3 video angles with reasoning.";

return [{ json: { systemPrompt, userMessage, slug } }];

const slug = $('Build Prompt').item.json.slug;
const responseText = $json.content[0].text;

// Extract content between delimiters if present
let output;
const startMarker = '---OUTPUT START---';
const endMarker = '---OUTPUT END---';
const startIdx = responseText.indexOf(startMarker);
const endIdx = responseText.indexOf(endMarker);

if (startIdx !== -1 && endIdx !== -1) {
  output = responseText.substring(startIdx + startMarker.length, endIdx).trim();
} else {
  output = responseText.trim();
}

return [{ json: { slug, notesContent: output } }];

const slug = $('Extract Response').item.json.slug;
const content = $('Extract Response').item.json.notesContent;

// Word count
const wordCount = content.split(/\s+/).filter(w => w.length > 0).length;

const lines = [
  'Research complete for: ' + slug,
  '',
  'Stats:',
  '  File: books/' + slug + '/notes.md',
  '  Characters: ' + content.length,
  '  Words: ' + wordCount,
  '',
  'Notes saved. Review in n8n or at books/' + slug + '/notes.md',
  '',
  'Next step: Run 03-Storyboard workflow to create storyboard.'
];

return [{ json: { summary: lines.join('\n') } }];
